{{Infobox royalty
| name            = Saionji Shōshi<br/>{{lang|ja|西園寺鏱子}}
| succession      = [[Japanese empresses|Empress consort of Japan]]
| reign           = 27 November 1288 – 27 September 1298
| reign-type      = Tenure
| spouse          = [[Emperor Fushimi]] 
| issue           = [[Emperor Go-Fushimi]] (adopted)
| royal house     = [[Imperial House of Japan]]
| father          = Saionji Sanekane
| mother          = Nakanoin Akiko
| birth_date      = 1271
